import { Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { AuthService } from '../../core/services/auth.service';
import { DepartmentService, TeamService, SkillService } from '../../core/services/api.services';
import { Department, Team, Skill } from '../../core/models';

@Component({ selector: 'app-register', templateUrl: './register.component.html' })
export class RegisterComponent implements OnInit {
  step = 1;
  form: any = {
    email: '', password: '', confirmPassword: '', firstName: '', lastName: '',
    role: 'EMPLOYEE', departmentId: null, teamId: null,
    skillIds: [], experienceYears: 0, maxCapacityHours: 45, bio: ''
  };
  departments: Department[] = [];
  teams: Team[] = [];
  skills: Skill[] = [];
  error = ''; loading = false;
  showPassword = false;

  get passwordCriteria() {
    const p = this.form.password || '';
    return {
      length: p.length >= 8,
      upper: /[A-Z]/.test(p),
      lower: /[a-z]/.test(p),
      digit: /[0-9]/.test(p),
      special: /[@#$%!^&+=*]/.test(p)
    };
  }

  get passwordStrength(): number {
    const c = this.passwordCriteria;
    let score = 0;
    if (c.length) score++;
    if (c.upper) score++;
    if (c.lower) score++;
    if (c.digit) score++;
    if (c.special) score++;
    return score;
  }

  get passwordStrengthLabel(): string {
    const s = this.passwordStrength;
    if (s === 0) return '';
    if (s <= 2) return 'Weak';
    if (s <= 4) return 'Good';
    return 'Strong';
  }

  get passwordStrengthColor(): string {
    const s = this.passwordStrength;
    if (s <= 2) return 'var(--danger)';
    if (s <= 4) return 'var(--warning)';
    return 'var(--success)';
  }

  constructor(
    private auth: AuthService,
    private router: Router,
    private deptService: DepartmentService,
    private teamService: TeamService,
    private skillService: SkillService
  ) {
    if (this.auth.isLoggedIn) this.router.navigate(['/dashboard']);
  }

  ngOnInit(): void {
    this.deptService.getAll().subscribe(r => { if (r.success) this.departments = r.data; });
    this.skillService.getAll().subscribe(r => { if (r.success) this.skills = r.data; });
  }

  onDeptChange(): void {
    this.form.teamId = null;
    if (this.form.departmentId) {
      this.teamService.getByDept(this.form.departmentId).subscribe(r => { if (r.success) this.teams = r.data; });
    }
  }

  toggleSkill(id: number): void {
    const idx = this.form.skillIds.indexOf(id);
    if (idx >= 0) this.form.skillIds.splice(idx, 1);
    else this.form.skillIds.push(id);
  }

  hasSkill(id: number): boolean { return this.form.skillIds.includes(id); }

  nextStep(): void {
    if (this.step === 1) {
      if (!this.form.email || !this.form.firstName || !this.form.lastName) {
        this.error = 'Please fill all required fields'; return;
      }
      const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
      if (!emailRegex.test(this.form.email)) {
        this.error = 'Invalid email format'; return;
      }
      const nameRegex = /^[a-zA-Z]+$/;
      if (!nameRegex.test(this.form.firstName) || !nameRegex.test(this.form.lastName)) {
        this.error = 'Name must contain only letters'; return;
      }
      if (this.form.firstName.length < 2 || this.form.lastName.length < 2) {
        this.error = 'Name must be at least 2 characters'; return;
      }
      if (!this.form.password) {
        this.error = 'Password is required'; return;
      }
      const passwordRegex = /^(?=.*[0-9])(?=.*[a-z])(?=.*[A-Z])(?=.*[@#$%!^&+=*]).{8,}$/;
      if (!passwordRegex.test(this.form.password)) {
        this.error = 'Password must be 8+ chars, have 1 upper, 1 lower, 1 digit, and 1 special char'; return;
      }
      if (this.form.password !== this.form.confirmPassword) {
        this.error = 'Passwords do not match'; return;
      }
    } else if (this.step === 2) {
      if (this.form.role !== 'PROJECT_MANAGER' && !this.form.departmentId) {
        this.error = 'Department is required for your role'; return;
      }
      const exp = this.form.experienceYears;
      const hrs = this.form.maxCapacityHours;

      if (exp === null || exp === undefined || exp < 0 || exp > 40) {
        this.error = 'Experience must be between 0 and 40 years'; return;
      }
      if (this.form.role === 'TEAM_LEAD') {
        if (hrs === null || hrs === undefined || hrs < 30 || hrs > 35) {
          this.error = 'Team Lead capacity must be between 30 and 35 hours'; return;
        }
      } else {
        if (hrs === null || hrs === undefined || hrs < 45 || hrs > 60) {
          this.error = 'Weekly capacity must be between 45 and 60 hours'; return;
        }
      }
    }
    this.error = '';
    this.step++;
  }

  register(): void {
    this.loading = true; this.error = '';
    const payload = { ...this.form };
    delete payload.confirmPassword;
    this.auth.register(payload).subscribe({
      next: (res) => {
        this.loading = false;
        if (res.success) this.router.navigate(['/dashboard']);
        else this.error = res.message;
      },
      error: (err) => { this.loading = false; this.error = err.error?.message || 'Registration failed'; }
    });
  }

  get roleLabel(): string {
    const map: any = { PROJECT_MANAGER: 'Project Manager', DEPARTMENT_HEAD: 'Department Head', TEAM_LEAD: 'Team Lead', EMPLOYEE: 'Employee' };
    return map[this.form.role] || this.form.role;
  }

  get skillCategories(): string[] {
    return [...new Set(this.skills.map(s => s.category || 'Other'))];
  }

  getSkillsByCategory(cat: string): Skill[] {
    return this.skills.filter(s => (s.category || 'Other') === cat);
  }

  onRoleChange(): void {
    if (this.form.role === 'TEAM_LEAD') {
      if (this.form.maxCapacityHours > 35 || this.form.maxCapacityHours < 30) {
        this.form.maxCapacityHours = 35;
      }
    } else {
      if (this.form.maxCapacityHours < 45 || this.form.maxCapacityHours > 60) {
        this.form.maxCapacityHours = 45;
      }
    }
  }
}
<div style="min-height:100vh;display:flex;align-items:center;justify-content:center;background:var(--bg);padding:20px">
  <div style="width:100%;max-width:480px">
    <div style="text-align:center;margin-bottom:28px">
      <a routerLink="/" style="display:inline-block;margin-bottom:12px;font-size:13px;color:var(--text-muted);text-decoration:none;">&larr; Back to Home</a>
      <br/>
      <div style="display:inline-flex;align-items:center;justify-content:center;width:56px;height:44px;background:var(--accent);border-radius:12px;font-size:20px;color:white;font-weight:800;margin-bottom:12px;letter-spacing:1px">ITA</div>
      <div style="font-size:18px;font-weight:800;color:var(--text-primary);margin-bottom:4px">Intelligent Task Allocator</div>
      <div style="font-size:14px;color:var(--text-secondary);margin-bottom:12px">Enterprise Task Management System</div>
      <div style="font-size:22px;font-weight:800;color:var(--text-primary)">Create Account</div>
    </div>

    <!-- Steps indicator -->
    <!-- Steps indicator -->
    <div style="display:flex;align-items:center;justify-content:center;margin-bottom:24px;padding:0 40px">
      <ng-container *ngFor="let s of [1,2,3]; let i=index">
        <div style="width:28px;height:28px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:12px;font-weight:700;flex-shrink:0"
          [style.background]="step > s ? 'var(--success)' : step === s ? 'var(--accent)' : 'var(--border)'"
          [style.color]="step >= s ? 'white' : 'var(--text-muted)'">{{ s }}</div>
        <div style="flex:1;height:2px;background:var(--border);margin:0 12px" *ngIf="i < 2"
          [style.background]="step > s ? 'var(--success)' : 'var(--border)'"></div>
      </ng-container>
    </div>

    <div class="card">
      <div class="card-body">
        <div *ngIf="error" style="background:var(--danger-subtle);border:1px solid rgba(239,68,68,0.2);border-radius:var(--radius-sm);padding:10px 14px;margin-bottom:16px;font-size:13px;color:var(--danger)">{{ error }}</div>

        <!-- Step 1: Basic Info -->
        <div *ngIf="step === 1" class="fade-in">
          <div style="font-size:15px;font-weight:700;margin-bottom:16px">Basic Information</div>
          <div class="two-col">
            <div class="form-group">
              <label class="form-label">First Name *</label>
              <input class="form-control" name="firstName" [(ngModel)]="form.firstName" #firstName="ngModel" placeholder="John" required minlength="2" pattern="^[a-zA-Z]+$">
              <div *ngIf="firstName.invalid && (firstName.dirty || firstName.touched)" style="color:var(--danger);font-size:12px;margin-top:4px">
                <span *ngIf="firstName.errors?.['required']">First name is required.</span>
                <span *ngIf="firstName.errors?.['minlength']">Must be at least 2 characters.</span>
                <span *ngIf="firstName.errors?.['pattern']">Only letters are allowed.</span>
              </div>
            </div>
            <div class="form-group">
              <label class="form-label">Last Name *</label>
              <input class="form-control" name="lastName" [(ngModel)]="form.lastName" #lastName="ngModel" placeholder="Doe" required minlength="2" pattern="^[a-zA-Z]+$">
              <div *ngIf="lastName.invalid && (lastName.dirty || lastName.touched)" style="color:var(--danger);font-size:12px;margin-top:4px">
                <span *ngIf="lastName.errors?.['required']">Last name is required.</span>
                <span *ngIf="lastName.errors?.['minlength']">Must be at least 2 characters.</span>
                <span *ngIf="lastName.errors?.['pattern']">Only letters are allowed.</span>
              </div>
            </div>
          </div>
          <div class="form-group">
            <label class="form-label">Email *</label>
            <input type="email" class="form-control" name="email" [(ngModel)]="form.email" #email="ngModel" placeholder="you@company.com" required pattern="^[^\s@]+@[^\s@]+\.[^\s@]+$">
            <div *ngIf="email.invalid && (email.dirty || email.touched)" style="color:var(--danger);font-size:12px;margin-top:4px">
              <span *ngIf="email.errors?.['required']">Email is required.</span>
              <span *ngIf="email.errors?.['pattern']">Invalid email format.</span>
            </div>
          </div>
          <div class="form-group">
            <label class="form-label">Password *</label>
            <div style="position:relative">
              <input [type]="showPassword ? 'text' : 'password'" class="form-control" name="password" [(ngModel)]="form.password" #password="ngModel" placeholder="Minimum 8 characters" required pattern="^(?=.*[0-9])(?=.*[a-z])(?=.*[A-Z])(?=.*[@#$%!^&+=*]).{8,}$" style="padding-right: 40px;">
              <button type="button" (click)="showPassword = !showPassword" style="position:absolute;right:10px;top:50%;transform:translateY(-50%);background:var(--bg-hover);border:1px solid var(--border);cursor:pointer;color:var(--text-secondary);font-size:11px;font-weight:600;padding:2px 8px;border-radius:4px;outline:none;text-transform:uppercase;" title="Toggle Password Visibility">
                <span *ngIf="showPassword">Hide</span>
                <span *ngIf="!showPassword">Show</span>
              </button>
            </div>
            <div *ngIf="form.password" style="margin-top:10px">
              <div style="display:flex;gap:4px;height:4px;margin-bottom:6px">
                <div style="flex:1;border-radius:2px;background:var(--border)" [style.background]="passwordStrength >= 1 ? passwordStrengthColor : 'var(--border)'"></div>
                <div style="flex:1;border-radius:2px;background:var(--border)" [style.background]="passwordStrength >= 3 ? passwordStrengthColor : 'var(--border)'"></div>
                <div style="flex:1;border-radius:2px;background:var(--border)" [style.background]="passwordStrength >= 5 ? passwordStrengthColor : 'var(--border)'"></div>
              </div>
              <div style="font-size:12px;font-weight:600" [style.color]="passwordStrengthColor">{{ passwordStrengthLabel }}</div>
              <div style="display:grid;grid-template-columns:1fr 1fr;gap:6px;margin-top:8px;font-size:11px;color:var(--text-muted)">
                <div [style.color]="passwordCriteria.length ? 'var(--success)' : ''">
                  <span *ngIf="passwordCriteria.length">✓</span><span *ngIf="!passwordCriteria.length">○</span> At least 8 characters
                </div>
                <div [style.color]="passwordCriteria.upper ? 'var(--success)' : ''">
                  <span *ngIf="passwordCriteria.upper">✓</span><span *ngIf="!passwordCriteria.upper">○</span> At least 1 uppercase letter
                </div>
                <div [style.color]="passwordCriteria.lower ? 'var(--success)' : ''">
                  <span *ngIf="passwordCriteria.lower">✓</span><span *ngIf="!passwordCriteria.lower">○</span> At least 1 lowercase letter
                </div>
                <div [style.color]="passwordCriteria.digit ? 'var(--success)' : ''">
                  <span *ngIf="passwordCriteria.digit">✓</span><span *ngIf="!passwordCriteria.digit">○</span> At least 1 number
                </div>
                <div [style.color]="passwordCriteria.special ? 'var(--success)' : ''" style="grid-column: 1 / -1">
                  <span *ngIf="passwordCriteria.special">✓</span><span *ngIf="!passwordCriteria.special">○</span> At least 1 special char (@#$%!^&+=*)
                </div>
              </div>
            </div>
            <div *ngIf="!form.password" style="color:var(--text-muted);font-size:12px;margin-top:6px">
              Password must contain at least 8 chars, including uppercase, lowercase, digit, and special char.
            </div>
          </div>
          <div class="form-group">
            <label class="form-label">Confirm Password *</label>
            <input type="password" class="form-control" name="confirmPassword" [(ngModel)]="form.confirmPassword" #confirmPassword="ngModel" placeholder="Repeat password" required>
            <div *ngIf="(confirmPassword.dirty || confirmPassword.touched) && form.password !== form.confirmPassword" style="color:var(--danger);font-size:12px;margin-top:4px">
              <span>Passwords do not match.</span>
            </div>
          </div>
          <button class="btn btn-primary w-full" style="justify-content:center;margin-top:4px" (click)="nextStep()">Continue →</button>
        </div>

        <!-- Step 2: Role & Org -->
        <div *ngIf="step === 2" class="fade-in">
          <div style="font-size:15px;font-weight:700;margin-bottom:16px">Role & Organization</div>
          <div class="form-group">
            <label class="form-label">Role *</label>
            <select class="form-control" [(ngModel)]="form.role" (ngModelChange)="onRoleChange()">
              <option value="EMPLOYEE">Employee</option>
              <option value="TEAM_LEAD">Team Lead</option>
              <option value="DEPARTMENT_HEAD">Department Head</option>
              <option value="PROJECT_MANAGER">Project Manager</option>
            </select>
          </div>
          <div class="form-group">
            <label class="form-label">Department</label>
            <select class="form-control" [(ngModel)]="form.departmentId" (ngModelChange)="onDeptChange()">
              <option [ngValue]="null">Select department...</option>
              <option *ngFor="let d of departments" [ngValue]="d.id">{{ d.name }}</option>
            </select>
          </div>
          <div class="form-group" *ngIf="form.departmentId && teams.length > 0">
            <label class="form-label">Team</label>
            <select class="form-control" [(ngModel)]="form.teamId">
              <option [ngValue]="null">Select team...</option>
              <option *ngFor="let t of teams" [ngValue]="t.id">{{ t.name }}</option>
            </select>
          </div>
          <div class="two-col">
            <div class="form-group">
              <label class="form-label">Experience (years)</label>
              <input type="number" class="form-control" [(ngModel)]="form.experienceYears" min="0" max="40">
            </div>
            <div class="form-group">
              <label class="form-label">Weekly Capacity (hrs)</label>
              <input type="number" class="form-control" [(ngModel)]="form.maxCapacityHours" 
                     [min]="form.role === 'TEAM_LEAD' ? 30 : 45" 
                     [max]="form.role === 'TEAM_LEAD' ? 35 : 60">
            </div>
          </div>
          <div class="form-group">
            <label class="form-label">Bio</label>
            <textarea class="form-control" [(ngModel)]="form.bio" placeholder="Brief introduction..."></textarea>
          </div>
          <div style="display:flex;gap:10px;margin-top:4px">
            <button class="btn btn-secondary" style="flex:1;justify-content:center" (click)="step=1">← Back</button>
            <button class="btn btn-primary" style="flex:2;justify-content:center" (click)="nextStep()">Continue →</button>
          </div>
        </div>

        <!-- Step 3: Skills -->
        <div *ngIf="step === 3" class="fade-in">
          <div style="font-size:15px;font-weight:700;margin-bottom:4px">Skills</div>
          <div style="font-size:13px;color:var(--text-muted);margin-bottom:16px">Select your technical skills</div>

          <div *ngFor="let cat of skillCategories" style="margin-bottom:14px">
            <div style="font-size:11px;font-weight:700;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.5px;margin-bottom:6px">{{ cat }}</div>
            <div style="display:flex;flex-wrap:wrap;gap:6px">
              <div *ngFor="let sk of getSkillsByCategory(cat)"
                (click)="toggleSkill(sk.id)"
                [style.background]="hasSkill(sk.id) ? 'var(--accent)' : 'var(--bg-hover)'"
                [style.color]="hasSkill(sk.id) ? 'white' : 'var(--text-secondary)'"
                [style.border]="hasSkill(sk.id) ? '1px solid var(--accent)' : '1px solid var(--border)'"
                style="padding:5px 12px;border-radius:99px;font-size:12px;font-weight:600;cursor:pointer;transition:all 0.15s">
                {{ sk.name }}
              </div>
            </div>
          </div>

          <div *ngIf="error" style="background:var(--danger-subtle);border:1px solid rgba(239,68,68,0.2);border-radius:var(--radius-sm);padding:10px 14px;margin-bottom:12px;font-size:13px;color:var(--danger)">{{ error }}</div>

          <div style="margin-top:8px">
            <div *ngIf="form.role === 'EMPLOYEE'" style="background:var(--warning-subtle);border:1px solid rgba(245,158,11,0.2);border-radius:var(--radius-sm);padding:10px 12px;font-size:12px;color:var(--warning);margin-bottom:12px">
              ⚠ Employee accounts require <strong>Project Manager approval</strong> before tasks can be assigned.
            </div>
            <div style="display:flex;gap:10px">
              <button class="btn btn-secondary" style="flex:1;justify-content:center" (click)="step=2">← Back</button>
              <button class="btn btn-primary" style="flex:2;justify-content:center" (click)="register()" [disabled]="loading">
                {{ loading ? 'Creating account...' : 'Create Account' }}
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>

    <div style="text-align:center;margin-top:16px;font-size:13px;color:var(--text-muted)">
      Already have an account?
      <a routerLink="/login" style="color:var(--accent);font-weight:600;margin-left:4px">Sign in</a>
    </div>
  </div>
</div>
